{
  "name": "Illinois Legal Assistance for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "Varies by provider; Prairie State Legal Services: generally <125% FPL, up to 200% FPL with certain expenses; Legal Aid Chicago: ≤150% FPL, higher for seniors/homeowners/veterans; older source: ≤$15,000 individual/$20,000 couple annually[2][3][4]",
    "asset_limits": "Limited assets required (specific limits not detailed uniformly; assessed by local providers)[1][2][3][4]",
    "other_requirements": ["Illinois resident", "U.S. citizen, lawful permanent resident, or specific non-citizen categories (e.g., asylee, refugee, certain visa holders)", "Civil legal issue relevant to seniors (e.g., healthcare denials, housing, benefits)", "Typically low-income priority, but seniors often qualify under expanded guidelines[1][3][4][6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free or reduced-fee civil legal assistance, including representation, advice, and advocacy on issues like Medicare/Medicaid denials, home care, housing, advance directives, long-term care, benefits appeals; no fixed dollar amounts or hours specified[6][8]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone: Senior Helpline (800) 252-8966 or (888) 206-1327 (TTY) to find local AAA[1][6]", "Contact local Area Agency on Aging (AAA) via https://ilaging.illinois.gov/ map tool[6]", "Prairie State Legal Services: Online intake via Illinois Legal Aid site or local office phone (e.g., 815.965.2134)[3]", "Legal Aid Chicago: Online eligibility tool for seniors in Suburban Cook County (Elder Risk Detector)[4]"],
    "processing_time": "Local agency decision within 30 days for related assessments (e.g., DON); legal aid screening upon contact[1]",
    "waitlist": "Limited resources may cause delays or denial due to capacity; no formal statewide waitlist specified[3][7]",
    "forms": ["Determination of Need (DON) for service need assessment (used by some agencies)[1]"],
    "documents": ["Proof of income and assets", "Court papers or important documents", "ID/residency proof", "Medicaid application if applicable[1][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Funded statewide via Area Agencies on Aging (AAAs); some providers regional (e.g., Prairie State: northern IL except Cook; Legal Aid Chicago: Chicago/Suburban Cook; Land of Lincoln: southern IL)[6][7]",
    "regional_variations": "Delivered by local AAAs contracting with legal aid providers; services, intake, and eligibility screening vary by AAA/provider/region; higher income thresholds for seniors in some programs[1][3][4][6][7]",
    "offices_or_providers": ["Local AAAs (find via https://ilaging.illinois.gov map)", "Prairie State Legal Services (northern IL)", "Legal Aid Chicago (Cook County)", "Land of Lincoln Legal Assistance (southern IL)[3][4][6][7]"]
  },
  "official_source": "https://ilaging.illinois.gov/programs/legalassistance.html",
  "gotchas": ["Not a single centralized program—must contact local AAA or provider; limited capacity means not everyone qualifies despite meeting criteria", "Focus on civil matters only (no criminal); seniors may need DON-like assessment for service need", "Income/asset guidelines vary and can be higher for seniors but still assessed case-by-case", "Must report changes if enrolled in related services[1][3][7]"],
  "data_shape_notes": "Decentralized network of local AAAs and legal aid providers with varying income/asset thresholds (often expanded for seniors); no uniform statewide income table or fixed benefits; regional providers handle delivery"
}
